class Solution:
    def minimumVisitedCells(self, grid):
        m, n = len(grid), len(grid[0])
        adj = [[[] for _ in range(n)] for _ in range(m)]
        for i in range(m):
            for j in range(n):
                reach = grid[i][j]
                right_max = min(j + reach, n - 1)
                for k in range(j + 1, right_max + 1):
                    adj[i][j].append((i, k))
                down_max = min(i + reach, m - 1)
                for k in range(i + 1, down_max + 1):
                    adj[i][j].append((k, j))
        from collections import deque
        dist = {(0, 0): 1}
        q = deque([(0, 0)])
        while q:
            cell = q.popleft()
            for nxt in adj[cell[0]][cell[1]]:
                if nxt not in dist:
                    dist[nxt] = dist[cell] + 1
                    q.append(nxt)
        return dist.get((m - 1, n - 1), -1)

