class Solution:
    def minimumVisitedCells(self, grid):
        from collections import deque
        m, n = len(grid), len(grid[0])
        dist = [[-1] * n for _ in range(m)]
        dist[0][0] = 1
        q = deque([(0, 0)])
        while q:
            i, j = q.popleft()
            if i == m - 1 and j == n - 1:
                return dist[i][j]
            d = dist[i][j]
            reach = grid[i][j]
            right_max = min(j + reach, n - 1)
            for k in range(j + 1, right_max + 1):
                if dist[i][k] == -1:
                    dist[i][k] = d + 1
                    q.append((i, k))
            down_max = min(i + reach, m - 1)
            for k in range(i + 1, down_max + 1):
                if dist[k][j] == -1:
                    dist[k][j] = d + 1
                    q.append((k, j))
        return -1

