var minimumVisitedCells = function(grid) {
    const m = grid.length, n = grid[0].length;
    const dist = Array.from({length: m}, () => new Array(n).fill(-1));
    dist[0][0] = 1;
    const queue = [[0, 0]];
    let head = 0;
    while (head < queue.length) {
        const [i, j] = queue[head++];
        if (i === m - 1 && j === n - 1) return dist[i][j];
        const d = dist[i][j];
        const reach = grid[i][j];
        const rightMax = Math.min(j + reach, n - 1);
        for (let k = j + 1; k <= rightMax; k++) {
            if (dist[i][k] === -1) { dist[i][k] = d + 1; queue.push([i, k]); }
        }
        const downMax = Math.min(i + reach, m - 1);
        for (let k = i + 1; k <= downMax; k++) {
            if (dist[k][j] === -1) { dist[k][j] = d + 1; queue.push([k, j]); }
        }
    }
    return -1;
};
